import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/chat_model.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/models/auth_utility.dart';
import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:calendario_financeiro/models/documento_model.dart';

class DocumentoService {
  final String baseUrl = "http://localhost:8080/api/documentos";

  Future<List<Documento>> getDocumentosPorData(DateTime data) async {
    final response = await http.get(
      Uri.parse('$baseUrl/data/${data.toIso8601String().substring(0, 10)}'),
    );

    if (response.statusCode == 200) {
      List<dynamic> body = json.decode(response.body);
      return body.map((dynamic item) => Documento.fromJson(item)).toList();
    } else {
      throw Exception('Falha ao carregar documentos');
    }
  }

  Future<List<Documento>> getDocumentosPorMesAno(int mes, int ano) async {
    final response = await http.get(
      Uri.parse('$baseUrl/mes/$mes/ano/$ano'),
    );

    if (response.statusCode == 200) {
      List<dynamic> body = json.decode(response.body);
      return body.map((dynamic item) => Documento.fromJson(item)).toList();
    } else {
      throw Exception('Falha ao carregar documentos do mês');
    }
  }

  Future<List<DateTime>> getDatasComDocumentos(int mes, int ano) async {
    final response = await http.get(
      Uri.parse('$baseUrl/datas/mes/$mes/ano/$ano'),
    );

    if (response.statusCode == 200) {
      List<dynamic> body = json.decode(response.body);
      return body.map<DateTime>((dateStr) => DateTime.parse(dateStr)).toList();
    } else {
      throw Exception('Falha ao carregar datas com documentos');
    }
  }

  Future<Documento> criarDocumento(Documento documento) async {
    final response = await http.post(
      Uri.parse(baseUrl),
      headers: <String, String>{
        'Content-Type': 'application/json; charset=UTF-8',
      },
      body: jsonEncode(documento.toJson()),
    );

    if (response.statusCode == 200) {
      return Documento.fromJson(json.decode(response.body));
    } else {
      throw Exception('Falha ao criar documento');
    }
  }
}
